# Terminal layout (buffer/window) and a short-path prompt for PowerShell.
# Integrated hosts (Cursor/VS Code) often block resizing; errors are ignored.
#
# Use in the current session:
#   . .\scripts\powershell-terminal-layout.ps1
# Or add that dot-source line to your PowerShell profile ($PROFILE).

param(
  [int]$BufferWidth = 120,
  [int]$BufferHeight = 9999,
  [int]$WindowWidth = 120,
  [int]$WindowHeight = 30,
  [switch]$SkipConsoleResize
)

if (-not $SkipConsoleResize) {
  try {
    $raw = $Host.UI.RawUI
    $raw.BufferSize = New-Object System.Management.Automation.Host.Size($BufferWidth, $BufferHeight)
    $raw.WindowSize = New-Object System.Management.Automation.Host.Size($WindowWidth, $WindowHeight)
  } catch {
    # Typical in Cursor/VS Code terminal or constrained hosts.
  }
}

function prompt {
  $leaf = Split-Path -Leaf -Path (Get-Location).Path
  "PS $leaf> "
}
